{
  "name": "StickerStreet",
  "description": "Une plateforme e-commerce Street Art sur Telegram pour vendre stickers et flyers en TON et Stars."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState, useEffect, useCallback, useRef } from 'react';

// --- TYPES ---

type ViewState = 'home' | 'product' | 'cart' | 'orders' | 'chat' | 'admin';
type PaymentMethod = 'stars' | 'ton';
type Category = 'all' | 'stickers' | 'flyers';
type OrderStatus = 'pending' | 'confirmed' | 'production' | 'shipped' | 'delivered';

interface Product {
  id: number;
  name: string;
  category: 'stickers' | 'flyers';
  priceStars: number;
  priceTon: number;
  emoji: string;
  sizes: string[];
  customizable: boolean;
  description: string;
}

interface CartItem extends Product {
  cartId: string;
  selectedSize: string;
  quantity: number;
  uploadedFile?: string;
}

interface Order {
  id: string;
  date: string;
  status: OrderStatus;
  items: CartItem[];
  totalStars: number;
  totalTon: number;
  paymentMethod: PaymentMethod;
}

interface ChatMessage {
  id: number;
  text: string;
  sender: 'user' | 'bot';
  timestamp: string;
}

// --- CONSTANTS & DATA ---

const COLORS = {
  bg: '#0D0D0D',
  card: '#1A1A1A',
  accent: '#FF3366', // Rose néon
  secondary: '#00FF88', // Vert néon
  tertiary: '#FFE156', // Jaune vif
  cyan: '#00D4FF',
  text: '#F0F0F0',
  textDim: '#888888',
  border: '#333333',
  ton: '#0098EA',
  stars: '#FFD700',
};

const PRODUCTS: Product[] = [
  { id: 1, name: "Sticker Skull Graffiti", category: 'stickers', priceStars: 2.50, priceTon: 0.40, emoji: "💀", sizes: ["5x5cm", "8x8cm", "10x10cm"], customizable: true, description: "Vinyle haute résistance, découpe précise. Le classique urbain indémodable." },
  { id: 2, name: "Pack Stickers Urban", category: 'stickers', priceStars: 8.00, priceTon: 1.20, emoji: "🎨", sizes: ["5x5cm", "8x8cm"], customizable: false, description: "Assortiment de 10 designs aléatoires par nos artistes partenaires." },
  { id: 3, name: "Sticker Tag Perso", category: 'stickers', priceStars: 3.50, priceTon: 0.50, emoji: "✏️", sizes: ["5x5cm", "8x8cm", "10x10cm", "15x15cm"], customizable: true, description: "Ton blaze, ton style. Upload ton design et on s'occupe du reste." },
  { id: 4, name: "Flyer Event A5", category: 'flyers', priceStars: 15.00, priceTon: 2.30, emoji: "📄", sizes: ["A5", "A4"], customizable: true, description: "Papier glacé 135g. Impression HD pour tes soirées et vernissages." },
  { id: 5, name: "Flyer Promo A4", category: 'flyers', priceStars: 25.00, priceTon: 3.80, emoji: "📰", sizes: ["A4", "A3"], customizable: true, description: "Impact maximum. Idéal pour affichage sauvage et promo massive." },
  { id: 6, name: "Sticker Holographique", category: 'stickers', priceStars: 4.00, priceTon: 0.60, emoji: "✨", sizes: ["5x5cm", "8x8cm"], customizable: true, description: "Effet arc-en-ciel qui change selon la lumière. Impossible à rater." },
  { id: 7, name: "Mega Pack Flyers", category: 'flyers', priceStars: 45.00, priceTon: 6.80, emoji: "📦", sizes: ["A5", "A4", "A3"], customizable: true, description: "500 exemplaires pour inonder la ville. Le meilleur rapport qualité/prix." },
  { id: 8, name: "Sticker Die-Cut", category: 'stickers', priceStars: 5.00, priceTon: 0.75, emoji: "⭐", sizes: ["Custom"], customizable: true, description: "Découpé à la forme exacte de ton logo. Finition pro matte ou brillante." },
];

const ORDER_STATUSES: Record<OrderStatus, { label: string; color: string; icon: string }> = {
  pending: { label: "En attente", color: COLORS.tertiary, icon: "⏳" },
  confirmed: { label: "Confirmée", color: "#56FFB2", icon: "✅" },
  production: { label: "Production", color: "#FF8C56", icon: "🔧" },
  shipped: { label: "Expédiée", color: COLORS.cyan, icon: "📦" },
  delivered: { label: "Livrée", color: "#56FF6E", icon: "🎉" },
};

const DEMO_ORDERS: Order[] = [
  {
    id: "ORD-2847",
    date: "14/02 10:30",
    status: 'production',
    totalStars: 12.50,
    totalTon: 0,
    paymentMethod: 'stars',
    items: [PRODUCTS[0] as unknown as CartItem, PRODUCTS[5] as unknown as CartItem] // Simplified for demo
  },
  {
    id: "ORD-2811",
    date: "10/02 18:45",
    status: 'delivered',
    totalStars: 0,
    totalTon: 2.80,
    paymentMethod: 'ton',
    items: [PRODUCTS[3] as unknown as CartItem]
  }
];

// --- ICONS (Inline SVG components for zero dependencies) ---

const Icons = {
  Home: ({ active }: { active: boolean }) => (
    <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke={active ? COLORS.accent : COLORS.textDim} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="m3 9 9-7 9 7v11a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2z"/><polyline points="9 22 9 12 15 12 15 22"/></svg>
  ),
  List: ({ active }: { active: boolean }) => (
    <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke={active ? COLORS.accent : COLORS.textDim} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M8 6h13"/><path d="M8 12h13"/><path d="M8 18h13"/><path d="M3 6h.01"/><path d="M3 12h.01"/><path d="M3 18h.01"/></svg>
  ),
  Message: ({ active }: { active: boolean }) => (
    <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke={active ? COLORS.accent : COLORS.textDim} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z"/></svg>
  ),
  Settings: ({ active }: { active: boolean }) => (
    <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke={active ? COLORS.accent : COLORS.textDim} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M12.22 2h-.44a2 2 0 0 0-2 2v.18a2 2 0 0 1-1 1.73l-.43.25a2 2 0 0 1-2 0l-.15-.08a2 2 0 0 0-2.73.73l-.22.38a2 2 0 0 0 .73 2.73l.15.1a2 2 0 0 1 1 1.72v.51a2 2 0 0 1-1 1.74l-.15.09a2 2 0 0 0-.73 2.73l.22.38a2 2 0 0 0 2.73.73l.15-.08a2 2 0 0 1 2 0l.43.25a2 2 0 0 1 1 1.73V20a2 2 0 0 0 2 2h.44a2 2 0 0 0 2-2v-.18a2 2 0 0 1 1-1.73l.43-.25a2 2 0 0 1 2 0l.15.08a2 2 0 0 0 2.73-.73l.22-.39a2 2 0 0 0-.73-2.73l-.15-.09a2 2 0 0 1-1-1.74v-.47a2 2 0 0 1 1-1.74l.15-.09a2 2 0 0 0 .73-2.73l-.22-.39a2 2 0 0 0-2.73-.73l-.15.08a2 2 0 0 1-2 0l-.43-.25a2 2 0 0 1-1-1.73V4a2 2 0 0 0-2-2z"/><circle cx="12" cy="12" r="3"/></svg>
  ),
  Cart: () => (
    <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><circle cx="8" cy="21" r="1"/><circle cx="19" cy="21" r="1"/><path d="M2.05 2.05h2l2.66 12.42a2 2 0 0 0 2 1.58h9.78a2 2 0 0 0 1.95-1.57l1.65-7.43H5.12"/></svg>
  ),
  ArrowLeft: () => (
    <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="m12 19-7-7 7-7"/><path d="M19 12H5"/></svg>
  ),
  Upload: () => (
    <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="17 8 12 3 7 8"/><line x1="12" x2="12" y1="3" y2="15"/></svg>
  ),
  Plus: () => (
    <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><path d="M5 12h14"/><path d="M12 5v14"/></svg>
  ),
  Minus: () => (
    <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><path d="M5 12h14"/></svg>
  ),
  Trash: () => (
     <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M3 6h18"/><path d="M19 6v14c0 1-1 2-2 2H7c-1 0-2-1-2-2V6"/><path d="M8 6V4c0-1 1-2 2-2h4c1 0 2 1 2 2v2"/></svg>
  ),
  Send: () => (
    <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><line x1="22" x2="11" y1="2" y2="13"/><polygon points="22 2 15 22 11 13 2 9 22 2"/></svg>
  )
};

// --- UTILS ---

const formatPrice = (amount: number, currency: PaymentMethod) => {
  return currency === 'stars' ? `${amount.toFixed(2)}` : `${amount.toFixed(2)}`;
};

// --- COMPONENTS ---

// 1. GRAIN OVERLAY
const GrainOverlay = () => (
  <div className="fixed inset-0 pointer-events-none z-50 opacity-[0.04]" 
    style={{
      backgroundImage: `url("data:image/svg+xml,%3Csvg viewBox='0 0 200 200' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='noiseFilter'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.65' numOctaves='3' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23noiseFilter)'/%3E%3C/svg%3E")`
    }}
  />
);

// 2. TOAST NOTIFICATION
const Toast = ({ message, show }: { message: string, show: boolean }) => {
  if (!show) return null;
  return (
    <div className="fixed top-20 left-1/2 transform -translate-x-1/2 z-[60] animate-bounce-in">
      <div 
        className="px-6 py-3 rounded-full flex items-center justify-center text-sm font-bold shadow-[0_4px_20px_#FF336644]"
        style={{ backgroundColor: COLORS.accent, color: 'white' }}
      >
        {message}
      </div>
    </div>
  );
};

// 3. MAIN APP
export default function StickerShopApp() {
  const [currentView, setCurrentView] = useState<ViewState>('home');
  const [cart, setCart] = useState<CartItem[]>([]);
  const [orders, setOrders] = useState<Order[]>(DEMO_ORDERS);
  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
  const [filterCategory, setFilterCategory] = useState<Category>('all');
  const [paymentMethod, setPaymentMethod] = useState<PaymentMethod>('ton');
  const [toast, setToast] = useState<{ show: boolean; msg: string }>({ show: false, msg: '' });

  // Scroll to top on view change
  useEffect(() => {
    window.scrollTo(0, 0);
  }, [currentView]);

  const showToast = (msg: string) => {
    setToast({ show: true, msg });
    setTimeout(() => setToast({ show: false, msg: '' }), 2500);
  };

  const addToCart = (product: Product, size: string, quantity: number, uploadedFile?: string) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id && item.selectedSize === size);
      if (existing) {
        return prev.map(item => 
          item === existing ? { ...item, quantity: item.quantity + quantity } : item
        );
      }
      return [...prev, { ...product, cartId: Math.random().toString(36), selectedSize: size, quantity, uploadedFile }];
    });
    showToast("Produit ajouté au panier ! 🛒");
  };

  const removeFromCart = (cartId: string) => {
    setCart(prev => prev.filter(item => item.cartId !== cartId));
  };

  const updateCartQuantity = (cartId: string, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.cartId === cartId) {
        const newQty = Math.max(1, item.quantity + delta);
        return { ...item, quantity: newQty };
      }
      return item;
    }));
  };

  const clearCart = () => setCart([]);

  const createOrder = () => {
    if (cart.length === 0) return;

    const totalStars = cart.reduce((acc, item) => acc + (item.priceStars * item.quantity), 0);
    const totalTon = cart.reduce((acc, item) => acc + (item.priceTon * item.quantity), 0);

    const newOrder: Order = {
      id: `ORD-${Math.floor(1000 + Math.random() * 9000)}`,
      date: new Date().toLocaleDateString('fr-FR', { day: '2-digit', month: '2-digit', hour: '2-digit', minute: '2-digit' }),
      status: 'pending',
      items: [...cart],
      totalStars,
      totalTon,
      paymentMethod
    };

    setOrders([newOrder, ...orders]);
    clearCart();
    setCurrentView('orders');
    showToast("Commande validée ! 🎉");
  };

  // --- SUB-COMPONENTS FOR VIEWS ---

  const Header = () => (
    <div className="fixed top-0 left-0 right-0 h-16 z-40 flex items-center justify-between px-4 border-b border-[#333] backdrop-blur-md bg-[#0D0D0D]/80">
      <div className="flex items-center gap-3">
        {currentView !== 'home' && (
          <button onClick={() => setCurrentView('home')} className="text-[#F0F0F0]">
            <Icons.ArrowLeft />
          </button>
        )}
        <div className="leading-tight cursor-pointer" onClick={() => setCurrentView('home')}>
          <div className="font-black tracking-[2px] text-lg">
            <span style={{ color: COLORS.accent }}>STICKER</span>
            <span style={{ color: COLORS.secondary }}>STREET</span>
          </div>
          <div className="text-[10px] text-[#888] tracking-[3px] font-bold">PRINT • STICK • REP</div>
        </div>
      </div>
      <button 
        onClick={() => setCurrentView('cart')}
        className="relative p-2 text-[#F0F0F0] hover:text-[#FF3366] transition-colors"
      >
        <Icons.Cart />
        {cart.length > 0 && (
          <span className="absolute top-1 right-0 w-4 h-4 bg-[#FF3366] rounded-full text-[10px] flex items-center justify-center font-bold text-white animate-pulse">
            {cart.reduce((a, b) => a + b.quantity, 0)}
          </span>
        )}
      </button>
    </div>
  );

  const BottomNav = () => (
    <div className="fixed bottom-0 left-0 right-0 h-20 z-40 flex justify-around items-start pt-4 border-t border-[#333] backdrop-blur-md bg-[#0D0D0D]/90 max-w-[480px] mx-auto">
      <button onClick={() => setCurrentView('home')} className="flex flex-col items-center gap-1">
        <Icons.Home active={currentView === 'home'} />
        <span className={`text-[10px] font-bold ${currentView === 'home' ? 'text-[#FF3366]' : 'text-[#888]'}`}>SHOP</span>
      </button>
      <button onClick={() => setCurrentView('orders')} className="flex flex-col items-center gap-1">
        <Icons.List active={currentView === 'orders'} />
        <span className={`text-[10px] font-bold ${currentView === 'orders' ? 'text-[#FF3366]' : 'text-[#888]'}`}>ORDRES</span>
      </button>
      <button onClick={() => setCurrentView('chat')} className="flex flex-col items-center gap-1">
        <Icons.Message active={currentView === 'chat'} />
        <span className={`text-[10px] font-bold ${currentView === 'chat' ? 'text-[#FF3366]' : 'text-[#888]'}`}>CHAT</span>
      </button>
      <button onClick={() => setCurrentView('admin')} className="flex flex-col items-center gap-1">
        <Icons.Settings active={currentView === 'admin'} />
        <span className={`text-[10px] font-bold ${currentView === 'admin' ? 'text-[#FF3366]' : 'text-[#888]'}`}>ADMIN</span>
      </button>
    </div>
  );

  // --- VIEW: HOME ---
  const HomeView = () => {
    const filteredProducts = PRODUCTS.filter(p => filterCategory === 'all' || p.category === filterCategory);

    return (
      <div className="pb-32 animate-fade-in-up">
        {/* HERO BANNER */}
        <div className="relative w-full h-64 mb-8 overflow-hidden rounded-b-[30px] border-b border-[#333]">
          <div className="absolute inset-0 bg-gradient-to-b from-[#1a1a2e] to-[#0D0D0D]" />
          <div className="absolute top-10 right-[-20px] text-[120px] opacity-10 rotate-12 select-none">🎨</div>
          <div className="absolute bottom-[-10px] left-[-20px] text-[80px] opacity-10 -rotate-12 select-none">🛹</div>

          <div className="relative z-10 p-6 flex flex-col justify-end h-full pb-8">
            <span className="inline-block px-3 py-1 mb-2 text-xs font-bold text-black bg-[#FFE156] w-fit rounded-full transform -rotate-2 shadow-[0_0_15px_#FFE15666]">
              🔥 NOUVEAU DROP
            </span>
            <h1 className="text-3xl font-black leading-none mb-1 tracking-tighter">
              TES DESIGNS<br/>
              <span className="text-transparent bg-clip-text bg-gradient-to-r from-[#FF3366] to-[#00D4FF]">SUR TOUT.</span>
            </h1>
            <p className="text-sm text-[#888] mb-4 font-bold">Stickers, flyers, ta créa prend vie ici.</p>
            <button 
              onClick={() => {
                const el = document.getElementById('catalog');
                el?.scrollIntoView({ behavior: 'smooth' });
              }}
              className="px-6 py-2 text-sm font-bold text-white rounded-lg shadow-[0_4px_20px_#FF336644] transition-transform active:scale-95 w-fit"
              style={{ background: COLORS.accent }}
            >
              VOIR LE CATALOGUE →
            </button>
          </div>
        </div>

        {/* FILTERS */}
        <div id="catalog" className="flex justify-center gap-2 mb-6 px-4">
          {(['all', 'stickers', 'flyers'] as Category[]).map(cat => (
            <button
              key={cat}
              onClick={() => setFilterCategory(cat)}
              className={`px-4 py-2 rounded-lg text-xs font-bold uppercase tracking-widest border transition-all ${
                filterCategory === cat 
                  ? 'border-[#FF3366] bg-[#FF336622] text-[#FF3366] shadow-[0_0_15px_#FF336633]' 
                  : 'border-[#333] bg-[#1A1A1A] text-[#888]'
              }`}
            >
              {cat === 'all' ? 'Tout' : cat}
            </button>
          ))}
        </div>

        {/* GRID */}
        <div className="grid grid-cols-2 gap-4 px-4">
          {filteredProducts.map(product => (
            <div 
              key={product.id}
              onClick={() => {
                setSelectedProduct(product);
                setCurrentView('product');
              }}
              className="relative group bg-[#1A1A1A] rounded-2xl border border-[#333] overflow-hidden cursor-pointer hover:border-[#FF3366] transition-colors"
            >
              {/* Image Area */}
              <div className="aspect-square bg-gradient-to-br from-[#252525] to-[#111] flex items-center justify-center text-6xl group-hover:scale-105 transition-transform duration-300">
                {product.emoji}
              </div>

              {/* Badges */}
              {product.customizable && (
                <div className="absolute top-2 left-2 px-2 py-0.5 rounded text-[10px] font-bold bg-[#00FF8822] text-[#00FF88] border border-[#00FF8844]">
                  PERSO
                </div>
              )}

              {/* Info */}
              <div className="p-3">
                <h3 className="font-bold text-sm truncate mb-1">{product.name}</h3>
                <div className="flex justify-between items-end">
                  <div className="flex flex-col text-xs font-mono">
                    <span className="text-[#FFD700]">{product.priceStars.toFixed(2)} ⭐</span>
                    <span className="text-[#0098EA]">{product.priceTon.toFixed(2)} 💎</span>
                  </div>
                  <button className="w-8 h-8 rounded-full bg-[#FF3366] flex items-center justify-center text-white shadow-[0_2px_10px_#FF336666] active:scale-90 transition-transform">
                    <Icons.Plus />
                  </button>
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>
    );
  };

  // --- VIEW: PRODUCT DETAIL ---
  const ProductView = () => {
    if (!selectedProduct) return null;
    const [size, setSize] = useState(selectedProduct.sizes[0]);
    const [qty, setQty] = useState(1);
    const [uploaded, setUploaded] = useState<string | null>(null);
    const fileInputRef = useRef<HTMLInputElement>(null);

    const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
      if (e.target.files && e.target.files[0]) {
        setUploaded(e.target.files[0].name);
        showToast("Fichier reçu ! 🎨");
      }
    };

    const totalPriceStars = selectedProduct.priceStars * qty;
    const totalPriceTon = selectedProduct.priceTon * qty;

    return (
      <div className="pb-32 animate-fade-in-up">
        {/* HERO */}
        <div className="relative w-full h-48 bg-gradient-to-br from-[#252525] to-[#0D0D0D] flex items-center justify-center border-b border-[#333]">
          <div className="text-[80px] drop-shadow-[0_10px_30px_rgba(0,0,0,0.5)] animate-float">
            {selectedProduct.emoji}
          </div>
        </div>

        <div className="px-5 py-6">
          <div className="flex items-center gap-2 mb-2">
            <span className="px-2 py-1 text-[10px] font-bold uppercase tracking-wider rounded bg-[#333] text-[#AAA]">
              {selectedProduct.category === 'stickers' ? '🏷️ STICKER' : '📄 FLYER'}
            </span>
            {selectedProduct.customizable && (
              <span className="px-2 py-1 text-[10px] font-bold uppercase tracking-wider rounded bg-[#00FF8822] text-[#00FF88] border border-[#00FF8844]">
                Custom
              </span>
            )}
          </div>

          <h1 className="text-2xl font-black uppercase mb-2">{selectedProduct.name}</h1>
          <p className="text-[#888] text-sm mb-6 leading-relaxed font-bold">
            {selectedProduct.description}
          </p>

          {/* SIZES */}
          <div className="mb-6">
            <label className="text-xs text-[#666] font-bold uppercase tracking-wider mb-2 block">Taille</label>
            <div className="flex flex-wrap gap-2">
              {selectedProduct.sizes.map(s => (
                <button
                  key={s}
                  onClick={() => setSize(s)}
                  className={`px-4 py-2 rounded-lg text-xs font-bold border transition-all ${
                    size === s
                      ? 'border-[#FF3366] bg-[#FF3366] text-white shadow-[0_4px_15px_#FF336644]'
                      : 'border-[#333] bg-[#1A1A1A] text-[#CCC]'
                  }`}
                >
                  {s}
                </button>
              ))}
            </div>
          </div>

          {/* QUANTITY */}
          <div className="mb-6">
            <label className="text-xs text-[#666] font-bold uppercase tracking-wider mb-2 block">Quantité</label>
            <div className="flex items-center gap-4 bg-[#1A1A1A] w-fit p-1 rounded-lg border border-[#333]">
