                      <button onClick={() => updateCartQuantity(item.cartId, -1)} className="w-5 h-5 flex items-center justify-center"><Icons.Minus /></button>
                      <span className="text-xs font-mono w-4 text-center">{item.quantity}</span>
                      <button onClick={() => updateCartQuantity(item.cartId, 1)} className="w-5 h-5 flex items-center justify-center"><Icons.Plus /></button>
                    </div>
                  </div>
                </div>
              ))}
            </div>

            {/* Footer */}
            <div className="mt-auto bg-[#1A1A1A] p-6 rounded-2xl border border-[#333] shadow-2xl">
              <div className="flex justify-between items-center mb-4">
                <span className="text-[#888] font-bold">Total</span>
                <span className="text-2xl font-black font-mono">
                  {formatPrice(total, paymentMethod)} {paymentMethod === 'stars' ? '⭐' : '💎'}
                </span>
              </div>
              <button 
                onClick={createOrder}
                className={`w-full py-3 rounded-xl font-bold flex items-center justify-center gap-2 shadow-[0_4px_20px_rgba(0,0,0,0.4)] active:scale-95 transition-transform ${
                  paymentMethod === 'stars' 
                    ? 'bg-gradient-to-r from-[#FFD700] to-[#FFC000] text-black' 
                    : 'bg-gradient-to-r from-[#0098EA] to-[#0077CC] text-white'
                }`}
              >
                PAYER EN {paymentMethod === 'stars' ? 'STARS ⭐' : 'TON 💎'}
              </button>
            </div>
          </>
        )}
      </div>
    );
  };

  // --- VIEW: ORDERS ---
  const OrdersView = () => (
    <div className="pb-32 px-4 pt-20 animate-fade-in-up">
      <h1 className="text-2xl font-black uppercase mb-6">📋 Mes Commandes</h1>
      <div className="space-y-4">
        {orders.map(order => {
          const statusConfig = ORDER_STATUSES[order.status];
          const statuses = Object.keys(ORDER_STATUSES) as OrderStatus[];
          const currentStatusIdx = statuses.indexOf(order.status);

          return (
            <div key={order.id} className="bg-[#1A1A1A] rounded-xl border border-[#333] p-5">
              <div className="flex justify-between items-start mb-4">
                <div>
                  <div className="font-bold text-lg text-white">{order.id}</div>
                  <div className="text-xs text-[#666] font-mono">{order.date}</div>
                </div>
                <div className={`px-2 py-1 rounded text-[10px] font-bold uppercase flex items-center gap-1 border`}
                  style={{ backgroundColor: `${statusConfig.color}22`, color: statusConfig.color, borderColor: `${statusConfig.color}44` }}
                >
                  {statusConfig.icon} {statusConfig.label}
                </div>
              </div>

              <div className="space-y-2 mb-4">
                {order.items.map((item, idx) => (
                  <div key={idx} className="flex justify-between text-sm text-[#CCC]">
                    <span>{item.quantity}x {item.name}</span>
                    <span className="text-[#666] text-xs">{item.selectedSize}</span>
                  </div>
                ))}
              </div>

              <div className="flex justify-between items-center pt-3 border-t border-[#333] mb-4">
                <span className="text-xs font-bold text-[#666]">TOTAL</span>
                <span className="font-mono font-bold">
                  {order.paymentMethod === 'stars' 
                    ? `${order.totalStars.toFixed(2)} ⭐` 
                    : `${order.totalTon.toFixed(2)} 💎`}
                </span>
              </div>

              {/* Progress Bar */}
              <div className="flex gap-1 h-1.5">
                {statuses.map((s, idx) => (
                  <div 
                    key={s} 
                    className={`flex-1 rounded-full transition-colors ${
                      idx <= currentStatusIdx ? 'bg-[#56FFB2]' : 'bg-[#333]'
                    }`}
                  />
                ))}
              </div>
            </div>
          );
        })}
      </div>
    );
  };

  // --- VIEW: CHAT ---
  const ChatView = () => {
    const [messages, setMessages] = useState<ChatMessage[]>([
      { id: 1, text: "Yo ! 👋 Bienvenue sur StickerStreet. Comment je peux t'aider ?", sender: 'bot', timestamp: '10:00' }
    ]);
    const [input, setInput] = useState("");
    const messagesEndRef = useRef<HTMLDivElement>(null);

    const scrollToBottom = () => {
      messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
    };

    useEffect(scrollToBottom, [messages]);

    const handleSend = () => {
      if (!input.trim()) return;
      const userMsg: ChatMessage = {
        id: Date.now(),
        text: input,
        sender: 'user',
        timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
      };
      setMessages(prev => [...prev, userMsg]);
      setInput("");

      // Bot Auto Reply
      setTimeout(() => {
        const replies = [
          "Je regarde ça tout de suite ! 🔍",
          "Pas de souci, on va trouver ce qu'il te faut 💪",
          "Super choix ! Tu veux qu'on personnalise ?",
          "Je te prépare un devis, 2 secondes ⚡",
          "Tu peux m'envoyer ton design et je te fais un aperçu 🎨"
        ];
        const randomReply = replies[Math.floor(Math.random() * replies.length)];
        const botMsg: ChatMessage = {
          id: Date.now() + 1,
          text: randomReply,
          sender: 'bot',
          timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
        };
        setMessages(prev => [...prev, botMsg]);
      }, 1200);
    };

    return (
      <div className="pb-24 pt-16 h-screen flex flex-col bg-[#0D0D0D]">
        <div className="fixed top-0 left-0 right-0 h-16 bg-[#0D0D0D]/90 backdrop-blur border-b border-[#333] z-20 flex items-center px-4 font-bold">
          <div className="w-2 h-2 rounded-full bg-[#56FF6E] mr-2 animate-pulse"/>
          Support StickerStreet
        </div>

        <div className="flex-1 overflow-y-auto px-4 py-4 space-y-4">
          {messages.map(msg => (
            <div key={msg.id} className={`flex flex-col ${msg.sender === 'user' ? 'items-end' : 'items-start'}`}>
              <div 
                className={`max-w-[80%] px-4 py-3 text-sm relative ${
                  msg.sender === 'user' 
                    ? 'bg-[#FF336622] border border-[#FF3366] text-white rounded-t-xl rounded-bl-xl' 
                    : 'bg-[#1A1A1A] border border-[#333] text-[#CCC] rounded-t-xl rounded-br-xl'
                }`}
              >
                {msg.text}
              </div>
              <span className="text-[10px] text-[#555] mt-1 font-mono">{msg.timestamp}</span>
            </div>
          ))}
          <div ref={messagesEndRef} />
        </div>

        <div className="fixed bottom-20 left-0 right-0 p-4 bg-[#0D0D0D] border-t border-[#333] flex gap-2 max-w-[480px] mx-auto">
          <input 
            type="text" 
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            placeholder="Écris ton message..."
            className="flex-1 bg-[#1A1A1A] border border-[#333] rounded-full px-4 py-2 text-sm text-white focus:border-[#FF3366] outline-none"
          />
          <button 
            onClick={handleSend}
            className="w-10 h-10 rounded-full bg-[#FF3366] flex items-center justify-center text-white shadow-[0_0_15px_#FF336644] active:scale-90 transition-transform"
          >
            <Icons.Send />
          </button>
        </div>
      </div>
    );
  };

  // --- VIEW: ADMIN ---
  const AdminView = () => {
    const [tab, setTab] = useState<'orders' | 'products'>('orders');

    const totalRevenueStars = orders.reduce((acc, o) => acc + o.totalStars, 0);
    const totalRevenueTon = orders.reduce((acc, o) => acc + o.totalTon, 0);
    const pendingCount = orders.filter(o => o.status === 'pending').length;

    const changeStatus = (orderId: string, newStatus: OrderStatus) => {
      setOrders(prev => prev.map(o => o.id === orderId ? { ...o, status: newStatus } : o));
    };

    return (
      <div className="pb-32 px-4 pt-20 animate-fade-in-up">
        <h1 className="text-2xl font-black uppercase mb-6 flex items-center gap-2">
          <span>⚙️</span> DASHBOARD
        </h1>

        {/* STATS */}
        <div className="grid grid-cols-2 gap-3 mb-8">
          <div className="bg-[#1A1A1A] p-4 rounded-xl border border-[#333]">
            <div className="text-[10px] text-[#888] font-bold uppercase mb-1">Revenus</div>
            <div className="font-mono font-bold text-[#FFD700] text-sm">{totalRevenueStars.toFixed(0)} ⭐</div>
            <div className="font-mono font-bold text-[#0098EA] text-sm">{totalRevenueTon.toFixed(2)} 💎</div>
          </div>
          <div className="bg-[#1A1A1A] p-4 rounded-xl border border-[#333]">
            <div className="text-[10px] text-[#888] font-bold uppercase mb-1">Commandes</div>
            <div className="text-2xl font-black text-white">{orders.length}</div>
          </div>
          <div className="bg-[#1A1A1A] p-4 rounded-xl border border-[#333]">
            <div className="text-[10px] text-[#888] font-bold uppercase mb-1">En attente</div>
            <div className="text-2xl font-black text-[#FFE156]">{pendingCount}</div>
          </div>
          <div className="bg-[#1A1A1A] p-4 rounded-xl border border-[#333]">
            <div className="text-[10px] text-[#888] font-bold uppercase mb-1">Produits</div>
            <div className="text-2xl font-black text-white">{PRODUCTS.length}</div>
          </div>
        </div>

        {/* TABS */}
        <div className="flex border-b border-[#333] mb-6">
          <button 
            onClick={() => setTab('orders')} 
            className={`px-4 py-2 text-sm font-bold border-b-2 transition-colors ${tab === 'orders' ? 'border-[#FF3366] text-[#FF3366]' : 'border-transparent text-[#888]'}`}
          >
            COMMANDES
          </button>
          <button 
            onClick={() => setTab('products')} 
            className={`px-4 py-2 text-sm font-bold border-b-2 transition-colors ${tab === 'products' ? 'border-[#FF3366] text-[#FF3366]' : 'border-transparent text-[#888]'}`}
          >
            PRODUITS
          </button>
        </div>

        {/* LIST */}
        <div className="space-y-4">
          {tab === 'orders' ? (
            orders.map(order => (
              <div key={order.id} className="bg-[#1A1A1A] p-4 rounded-xl border border-[#333]">
                <div className="flex justify-between mb-3">
                  <span className="font-bold text-sm">{order.id}</span>
                  <span className="font-mono text-xs text-[#666]">{order.date}</span>
                </div>
                <div className="flex flex-wrap gap-2">
                  {(Object.keys(ORDER_STATUSES) as OrderStatus[]).map(s => (
                    <button 
                      key={s}
                      onClick={() => changeStatus(order.id, s)}
                      title={ORDER_STATUSES[s].label}
                      className={`w-8 h-8 rounded flex items-center justify-center text-sm border transition-all ${
                        order.status === s 
                          ? `bg-[${ORDER_STATUSES[s].color}22] border-[${ORDER_STATUSES[s].color}] scale-110 shadow-lg` 
                          : 'bg-[#0D0D0D] border-[#333] opacity-50 hover:opacity-100'
                      }`}
                      style={{ 
                        backgroundColor: order.status === s ? `${ORDER_STATUSES[s].color}33` : undefined,
                        borderColor: order.status === s ? ORDER_STATUSES[s].color : '#333'
                       }}
                    >
                      {ORDER_STATUSES[s].icon}
                    </button>
                  ))}
                </div>
              </div>
            ))
          ) : (
            PRODUCTS.map(product => (
              <div key={product.id} className="bg-[#1A1A1A] p-3 rounded-xl border border-[#333] flex items-center gap-3">
                <div className="text-2xl">{product.emoji}</div>
                <div>
                  <div className="font-bold text-sm">{product.name}</div>
                  <div className="text-xs text-[#666] font-mono">
                    {product.priceStars}⭐ | {product.priceTon}💎
                  </div>
                </div>
              </div>
            ))
          )}
        </div>
      </div>
    );
  };

  // --- MAIN RENDER ---

  const renderView = () => {
    switch (currentView) {
      case 'home': return <HomeView />;
      case 'product': 
        return selectedProduct ? (
          <ProductView 
            product={selectedProduct} 
            onAddToCart={addToCart} 
            onBack={() => setCurrentView('home')} 
            showToast={showToast} 
          />
        ) : null;
      case 'cart': return <CartView />;
      case 'orders': return <OrdersView />;
      case 'chat': return <ChatView />;
      case 'admin': return <AdminView />;
      default: return <HomeView />;
    }
  };

  return (
    <div className="min-h-screen text-[#F0F0F0] relative overflow-hidden font-mono max-w-[480px] mx-auto bg-[#0D0D0D] shadow-2xl">
      <style>{`
        @keyframes float { 0% { transform: translateY(0px); } 50% { transform: translateY(-10px); } 100% { transform: translateY(0px); } }
        .animate-float { animation: float 3s ease-in-out infinite; }
        @keyframes fadeInUp { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }
        .animate-fade-in-up { animation: fadeInUp 0.3s ease-out; }
        @keyframes bounceIn { 0% { opacity: 0; transform: translate(-50%, -20px); } 50% { opacity: 1; transform: translate(-50%, 5px); } 100% { transform: translate(-50%, 0); } }
        .animate-bounce-in { animation: bounceIn 0.3s cubic-bezier(0.175, 0.885, 0.32, 1.275); }
      `}</style>

      <GrainOverlay />
      <Toast show={toast.show} message={toast.msg} />

      <Header />

      <main className="relative z-10 pt-16">
        {renderView()}
      </main>

      <BottomNav />
    </div>
  );
}

import React, { useState, useEffect, useCallback, useRef } from 'react';

// --- TYPES ---

type ViewState = 'home' | 'product' | 'cart' | 'orders' | 'chat' | 'admin';
type PaymentMethod = 'stars' | 'ton';
type Category = 'all' | 'stickers' | 'flyers';
type OrderStatus = 'pending' | 'confirmed' | 'production' | 'shipped' | 'delivered';

interface Product {
  id: number;
  name: string;
  category: 'stickers' | 'flyers';
  priceStars: number;
  priceTon: number;
  emoji: string;
  sizes: string[];
  customizable: boolean;
  description: string;
}

interface CartItem extends Product {
  cartId: string;
  selectedSize: string;
  quantity: number;
  uploadedFile?: string;
}

interface Order {
  id: string;
  date: string;
  status: OrderStatus;
  items: CartItem[];
  totalStars: number;
  totalTon: number;
  paymentMethod: PaymentMethod;
}

interface ChatMessage {
  id: number;
  text: string;
  sender: 'user' | 'bot';
  timestamp: string;
}

