// 3. PRODUCT VIEW COMPONENT
const ProductView = ({ product, onAddToCart, onBack, showToast, isFavorite, toggleFavorite }: { 
  product: Product; 
  onAddToCart: (p: Product, s: string, q: number, f?: string | undefined) => void; 
  onBack: () => void;
  showToast: (msg: string) => void;
  isFavorite: boolean;
  toggleFavorite: () => void;
}) => {
    const [size, setSize] = useState(product.sizes[0]);
    const [qty, setQty] = useState(1);
    const [uploaded, setUploaded] = useState<string | null>(null);
    const [previewUrl, setPreviewUrl] = useState<string | null>(null);
    const [isLoading, setIsLoading] = useState(true);
    const fileInputRef = useRef<HTMLInputElement>(null);

    useEffect(() => {
        setIsLoading(true);
        const timer = setTimeout(() => setIsLoading(false), 800);
        return () => clearTimeout(timer);
    }, [product]);

    const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (!file) return;

      // Reset previous state
      setUploaded(null);
      setPreviewUrl(null);

      // Validation: Size (Max 10MB)
      if (file.size > 10 * 1024 * 1024) {
          showToast("Erreur: Fichier > 10MB ⚠️");
          if (fileInputRef.current) fileInputRef.current.value = "";
          return;
      }

      // Validation: Type
      const validTypes = ['image/png', 'image/jpeg', 'image/jpg', 'image/svg+xml', 'application/pdf'];
      if (!validTypes.includes(file.type)) {
          showToast("Type invalide (PNG, JPG, PDF) ⚠️");
          if (fileInputRef.current) fileInputRef.current.value = "";
          return;
      }

      // Success path
      setUploaded(file.name);

      if (file.type.startsWith('image/')) {
          const reader = new FileReader();
          reader.onload = () => {
              setPreviewUrl(reader.result as string);
              showToast("Fichier reçu ! 🎨");
          };
          reader.onerror = () => {
              showToast("Erreur lecture fichier ❌");
              setUploaded(null);
              setPreviewUrl(null);
          };
          reader.readAsDataURL(file);
      } else {
          showToast("Fichier reçu ! 🎨");
      }
    };

    const totalPriceStars = product.priceStars * qty;
    const totalPriceTon = product.priceTon * qty;

    if (isLoading) {
       return (
         <div className="pb-32 animate-fade-in-up">
            {/* HERO SKELETON */}
            <div className="relative w-full h-48 bg-[#1A1A1A] animate-pulse border-b border-[#333]"></div>

            <div className="px-5 py-6 space-y-6">
                <div className="flex gap-2">
                    <div className="h-6 w-20 bg-[#1A1A1A] rounded animate-pulse"></div>
                    <div className="h-6 w-16 bg-[#1A1A1A] rounded animate-pulse"></div>
                </div>
                <div className="space-y-2">
                    <div className="h-8 w-3/4 bg-[#1A1A1A] rounded animate-pulse"></div>
                    <div className="h-4 w-full bg-[#1A1A1A] rounded animate-pulse"></div>
                    <div className="h-4 w-5/6 bg-[#1A1A1A] rounded animate-pulse"></div>
                </div>
                <div className="space-y-2">
                     <div className="h-4 w-12 bg-[#1A1A1A] rounded animate-pulse"></div>
                     <div className="flex gap-2">
                        <div className="h-10 w-24 bg-[#1A1A1A] rounded animate-pulse"></div>
                        <div className="h-10 w-24 bg-[#1A1A1A] rounded animate-pulse"></div>
                     </div>
                </div>
                <div className="space-y-2">
                     <div className="h-4 w-16 bg-[#1A1A1A] rounded animate-pulse"></div>
                     <div className="h-12 w-32 bg-[#1A1A1A] rounded animate-pulse"></div>
                </div>
                <div className="h-16 w-full bg-[#1A1A1A] rounded-xl animate-pulse mt-8"></div>
            </div>
        </div>
       );
    }

    return (
      <div className="pb-32 animate-fade-in-up">
        {/* HERO */}
        <div className="relative w-full h-48 bg-gradient-to-br from-[#252525] to-[#0D0D0D] flex items-center justify-center border-b border-[#333]">
          <div className="text-[80px] drop-shadow-[0_10px_30px_rgba(0,0,0,0.5)] animate-float">
            {product.emoji}
          </div>
          <button
            onClick={toggleFavorite}
            className="absolute top-4 right-4 z-10 p-3 rounded-full bg-black/50 backdrop-blur-sm text-white hover:bg-black/70 transition-colors"
          >
            <Icons.Heart filled={isFavorite} />
          </button>
        </div>

        <div className="px-5 py-6">
          <div className="flex items-center gap-2 mb-2">
            <span className="px-2 py-1 text-[10px] font-bold uppercase tracking-wider rounded bg-[#333] text-[#AAA]">
              {product.category === 'stickers' ? '🏷️ STICKER' : '📄 FLYER'}
            </span>
            {product.customizable && (
              <span className="px-2 py-1 text-[10px] font-bold uppercase tracking-wider rounded bg-[#00FF8822] text-[#00FF88] border border-[#00FF8844]">
                Custom
              </span>
            )}
          </div>

          <h1 className="text-2xl font-black uppercase mb-2">{product.name}</h1>
          <p className="text-[#888] text-sm mb-6 leading-relaxed font-bold">
            {product.description}
          </p>

          {/* SIZES */}
          <div className="mb-6">
            <label className="text-xs text-[#666] font-bold uppercase tracking-wider mb-2 block">Taille</label>
            <div className="flex flex-wrap gap-2">
              {product.sizes.map(s => (
                <button
                  key={s}
                  onClick={() => setSize(s)}
                  className={`px-4 py-2 rounded-lg text-xs font-bold border transition-all ${
                    size === s
                      ? 'border-[#FF3366] bg-[#FF3366] text-white shadow-[0_4px_15px_#FF336644]'
                      : 'border-[#333] bg-[#1A1A1A] text-[#CCC]'
                  }`}
                >
                  {s}
                </button>
              ))}
            </div>
          </div>

          {/* QUANTITY */}
          <div className="mb-6">
            <label className="text-xs text-[#666] font-bold uppercase tracking-wider mb-2 block">Quantité</label>
            <div className="flex items-center gap-4 bg-[#1A1A1A] w-fit p-1 rounded-lg border border-[#333]">
              <button onClick={() => setQty(Math.max(1, qty - 1))} className="w-10 h-10 flex items-center justify-center hover:bg-[#333] rounded transition-colors text-[#FFF]"><Icons.Minus /></button>
              <span className="font-mono text-lg w-8 text-center">{qty}</span>
              <button onClick={() => setQty(qty + 1)} className="w-10 h-10 flex items-center justify-center hover:bg-[#333] rounded transition-colors text-[#FFF]"><Icons.Plus /></button>
            </div>
          </div>

          {/* UPLOAD */}
          {product.customizable && (
            <div className="mb-8">
              <label className="text-xs text-[#666] font-bold uppercase tracking-wider mb-2 block">Design (Fichier)</label>
              <div 
                onClick={() => fileInputRef.current?.click()}
                className={`border-2 border-dashed rounded-xl p-6 flex flex-col items-center justify-center cursor-pointer transition-colors relative overflow-hidden ${
                  uploaded ? 'border-[#00FF88] bg-[#00FF8811]' : 'border-[#333] bg-[#1A1A1A] hover:border-[#666]'
                }`}
              >
                <input type="file" ref={fileInputRef} className="hidden" onChange={handleFileChange} accept="image/png, image/jpeg, image/svg+xml, application/pdf" />

                {previewUrl && (
                    <div className="absolute inset-0 opacity-30 pointer-events-none">
                        <img src={previewUrl} alt="Preview" className="w-full h-full object-cover filter blur-[2px]" />
                    </div>
                )}

                {uploaded ? (
                  <div className="relative z-10 flex flex-col items-center">
                    {previewUrl && (
                        <div className="w-16 h-16 mb-2 rounded-lg overflow-hidden border border-[#00FF88] shadow-[0_0_15px_#00FF8844]">
                            <img src={previewUrl} alt="Preview" className="w-full h-full object-cover" />
                        </div>
                    )}
                    {!previewUrl && <div className="text-[#00FF88] text-2xl mb-2">✅</div>}
                    <span className="text-xs text-[#00FF88] font-bold truncate max-w-[200px]">{uploaded}</span>
                    <span className="text-[10px] text-[#666] mt-1">Cliquer pour changer</span>
                  </div>
                ) : (
                  <>
                    <div className="text-[#FF3366] mb-2"><Icons.Upload /></div>
                    <span className="text-xs font-bold text-[#CCC]">Glisse ton fichier ici</span>
                    <span className="text-[10px] text-[#666] mt-1">PNG, JPG, PDF (Max 10MB)</span>
                  </>
                )}
              </div>
            </div>
          )}

          {/* ACTIONS */}
          <div className="flex items-center justify-between mb-4">
            <div className="flex flex-col">
              <span className="text-[#FFD700] font-bold text-xl">{totalPriceStars.toFixed(2)} ⭐</span>
              <span className="text-[#0098EA] font-bold text-sm">{totalPriceTon.toFixed(2)} TON</span>
            </div>
          </div>

          <button
            onClick={() => {
              onAddToCart(product, size, qty, uploaded || undefined);
              onBack();
            }}
            className="w-full py-4 rounded-xl text-white font-black tracking-widest text-lg shadow-[0_4px_25px_#FF336655] active:scale-95 transition-transform"
            style={{ background: COLORS.accent }}
          >
            AJOUTER AU PANIER 🛒
          </button>
        </div>
      </div>
    );
};

